pipeline.evaluate:
(async () => {
  const rawUrl = ${{ args.url | json }};
  const tweetId = String(rawUrl || '').match(/\/status\/(\d+)/)?.[1] || String(rawUrl || '').match(/^(\d+)$/)?.[1] || '';
  if (!tweetId) return [{ status: 'failed', message: 'Could not parse tweet ID from URL' }];

  const ct0 = document.cookie.split(';').map(c => c.trim()).find(c => c.startsWith('ct0='))?.split('=')[1];
  const bearer = 'AAAAAAAAAAAAAAAAAAAAANRILgAAAAAAnNwIzUejRCOuH5E6I8xnZz4puTs%3D1Zv7ttfk8LF81IUq16cHjhLTvJu4FA33AGWWjCpTnA';
  const headers = {
    Authorization: 'Bearer ' + decodeURIComponent(bearer),
    'X-Csrf-Token': ct0 || '',
    'X-Twitter-Auth-Type': 'OAuth2Session',
    'X-Twitter-Active-User': 'yes',
    'Content-Type': 'application/json'
  };

  const apiTargets = [
    `https://api.x.com/2/tweets/${tweetId}/hidden`,
    `/i/api/2/tweets/${tweetId}/hidden`
  ];

  for (const apiUrl of apiTargets) {
    try {
      const resp = await fetch(apiUrl, {
        method: 'PUT',
        credentials: 'include',
        headers,
        body: JSON.stringify({ hidden: true })
      });
      if (resp.ok) {
        let data = null;
        try { data = await resp.json(); } catch {}
        if (!data || data.data?.hidden === true || data.hidden === true) {
          return [{ status: 'success', message: 'Reply successfully hidden via API' }];
        }
      }
    } catch {}
  }

  const getPrimaryTweet = () => document.querySelector('[data-testid="primaryColumn"] article[data-testid="tweet"]') || document.querySelector('main article[data-testid="tweet"]') || document.querySelector('article[data-testid="tweet"]');
  const menuSelectors = [
    '[aria-label="More"]',
    '[aria-label="More menu items"]',
    '[data-testid="caret"]',
    'button[aria-haspopup="menu"]'
  ];
  const findMenuButton = () => {
    const roots = [getPrimaryTweet(), document].filter(Boolean);
    for (const root of roots) {
      for (const selector of menuSelectors) {
        const button = root.querySelector(selector);
        if (button) return button;
      }
    }
    return null;
  };
  const findMenuItem = (matcher) => {
    for (const item of document.querySelectorAll('[role="menuitem"]')) {
      const text = (item.textContent || '').trim();
      if (matcher(text)) return item;
    }
    return null;
  };

  let moreMenu = null;
  for (let attempts = 0; attempts < 20 && !moreMenu; attempts += 1) {
    moreMenu = findMenuButton();
    if (!moreMenu) await new Promise(r => setTimeout(r, 500));
  }

  if (!moreMenu) return [{ status: 'failed', message: 'Could not find More menu' }];

  moreMenu.click();
  await new Promise(r => setTimeout(r, 1000));

  let hideItem = null;
  for (let attempts = 0; attempts < 10 && !hideItem; attempts += 1) {
    hideItem = findMenuItem(text => text.includes('Hide reply'));
    if (!hideItem) await new Promise(r => setTimeout(r, 300));
  }

  if (!hideItem) return [{ status: 'failed', message: 'Hide reply option not found' }];

  hideItem.click();
  await new Promise(r => setTimeout(r, 1500));
  return [{ status: 'success', message: 'Reply successfully hidden' }];
})()
